.emulator-fullscreen-workaround {
    position: fixed !important;
    left: 0;
    top: 0;
    bottom: 0;
    right: 0;
    background: black;
    z-index: 999;
}

.emulator-button-touch-zone,
.emulator-button {
    cursor: pointer;
    -webkit-touch-callout: none;
    -webkit-user-select: none;
    -khtml-user-select: none;
    -moz-user-select: none;
    -ms-user-select: none;
    user-select: none;
    touch-action: none;

    overflow: hidden;
    background: none;
    color: rgb(255, 255, 255);

    border-radius: 50%;
    filter: opacity(0.8);
}

.emulator-button-touch-zone {
    display: flex;
    align-items: center;
    justify-content: center;

    border-color: rgba(255, 255, 255, 0.5);

    border-style: solid;
    box-shadow: 0 0 2px 2px rgba(255, 255, 255, 0.5),
        inset 0 0 2px 2px rgba(255, 255, 255, 0.5);
}

.emulator-button {
    position: absolute;
    background-color: rgba(128, 128, 128, 0.5);
    background-size: 50%;
    background-repeat: no-repeat;
    background-position: center;

    border: 1px solid rgb(255, 255, 255);
    text-shadow: -1px -1px 0 rgb(0, 0, 0), 1px -1px 0 rgb(0, 0, 0),
        -1px 1px 0 rgb(0, 0, 0), 1px 1px 0 rgb(0, 0, 0);
    text-align: center;
    box-shadow: 0px 0px 0px 1px rgb(0, 0, 0);
}

.emulator-button-text {
}

.emulator-control-select:hover,
.emulator-button-touch-zone:hover {
    filter: opacity(1) hue-rotate(-70deg) saturate(5) sepia(1);
}

.emulator-button-touch-zone.emulator-button-control {
    filter: opacity(1) !important;
    background-color: rgb(128, 128, 128) !important;
    z-index: 999;
}

.emulator-button-highlight,
.emulator-button-control:hover {
    filter: opacity(1) hue-rotate(-70deg) saturate(5) sepia(1) !important;
}

.emulator-control-select {
    overflow: hidden;
    background: none;
    color: white;
    border-radius: 10%;
    border: 1px solid rgb(255, 255, 255);
    box-shadow: 0px 0px 0px 1px rgb(0, 0, 0);

    -webkit-touch-callout: none;
    -webkit-user-select: none;
    -khtml-user-select: none;
    -moz-user-select: none;
    -ms-user-select: none;
    user-select: none;
    touch-action: none;
    filter: opacity(0.7);
}

.emulator-options {
    justify-content: flex-end;
    flex-wrap: wrap-reverse;
    display: flex;
    flex-direction: row;
    -webkit-touch-callout: none;
    -webkit-user-select: none;
    -khtml-user-select: none;
    -moz-user-select: none;
    -ms-user-select: none;
    user-select: none;
    touch-action: none;
}

.emulator-keyboard {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 999;
    color: black;
    -webkit-touch-callout: none;
    -webkit-user-select: none;
    -khtml-user-select: none;
    -moz-user-select: none;
    -ms-user-select: none;
    user-select: none;
    touch-action: none;
}

/* notyf */
@-webkit-keyframes notyf-fadeinup {
    0% {
        opacity: 0;
        transform: translateY(25%);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}
@keyframes notyf-fadeinup {
    0% {
        opacity: 0;
        transform: translateY(25%);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}
@-webkit-keyframes notyf-fadeinleft {
    0% {
        opacity: 0;
        transform: translateX(25%);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}
@keyframes notyf-fadeinleft {
    0% {
        opacity: 0;
        transform: translateX(25%);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}
@-webkit-keyframes notyf-fadeoutright {
    0% {
        opacity: 1;
        transform: translateX(0);
    }
    to {
        opacity: 0;
        transform: translateX(25%);
    }
}
@keyframes notyf-fadeoutright {
    0% {
        opacity: 1;
        transform: translateX(0);
    }
    to {
        opacity: 0;
        transform: translateX(25%);
    }
}
@-webkit-keyframes notyf-fadeoutdown {
    0% {
        opacity: 1;
        transform: translateY(0);
    }
    to {
        opacity: 0;
        transform: translateY(25%);
    }
}
@keyframes notyf-fadeoutdown {
    0% {
        opacity: 1;
        transform: translateY(0);
    }
    to {
        opacity: 0;
        transform: translateY(25%);
    }
}
@-webkit-keyframes ripple {
    0% {
        transform: scale(0) translateY(-45%) translateX(13%);
    }
    to {
        transform: scale(1) translateY(-45%) translateX(13%);
    }
}
@keyframes ripple {
    0% {
        transform: scale(0) translateY(-45%) translateX(13%);
    }
    to {
        transform: scale(1) translateY(-45%) translateX(13%);
    }
}
.notyf {
    position: fixed;
    top: 0;
    left: 0;
    height: 100%;
    width: 100%;
    color: #fff;
    z-index: 9999;
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    justify-content: flex-end;
    pointer-events: none;
    box-sizing: border-box;
    padding: 20px;
}
.notyf__icon--error,
.notyf__icon--success {
    height: 21px;
    width: 21px;
    background: #fff;
    border-radius: 50%;
    display: block;
    margin: 0 auto;
    position: relative;
}
.notyf__icon--error:after,
.notyf__icon--error:before {
    content: '';
    background: currentColor;
